    ... &amp;#123; role: &amp;quot;dbAdmin&amp;quot;,db: &amp;quot;03db&amp;quot; &amp;#125;,
    ... &amp;#123; role: &amp;quot;userAdmin&amp;quot;,db: &amp;quot;04db&amp;quot; &amp;#125; ]
    ...     &amp;#125;
