 &lt;h5 id=&#34;监控指标&#34;&gt;&lt;a href=&#34;#监控指标&#34; class=&#34;headerlink&#34; title=&#34;监控指标&#34;&gt;&lt;/a&gt;监控指标&lt;/h5&gt;&lt;ul&gt;
&lt;li&gt;性能指标：Performance&lt;/li&gt;
&lt;li&gt;内存指标: Memory&lt;/li&gt;
&lt;li&gt;基本活动指标：Basic activity&lt;/li&gt;
&lt;li&gt;持久性指标: Persistence&lt;/li&gt;
&lt;li&gt;错误指标：Error&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;h5 id=&#34;性能指标：Performance&#34;&gt;&lt;a href=&#34;#性能指标：Performance&#34; class=&#34;headerlink&#34; title=&#34;性能指标：Performance&#34;&gt;&lt;/a&gt;性能指标：Performance&lt;/h5&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;table-container&#34;&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;latency&lt;/td&gt;
&lt;td&gt;Redis响应一个请求的时间&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;instantaneous_ops_per_sec&lt;/td&gt;
&lt;td&gt;平均每秒处理请求总数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;hi rate(calculated)&lt;/td&gt;
&lt;td&gt;缓存命中率（计算出来的&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/div&gt;
&lt;h5 id=&#34;内存指标-Memory&#34;&gt;&lt;a href=&#34;#内存指标-Memory&#34; class=&#34;headerlink&#34; title=&#34;内存指标: Memory&#34;&gt;&lt;/a&gt;内存指标: Memory&lt;/h5&gt;&lt;div class=&#34;table-container&#34;&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;used_memory&lt;/td&gt;
&lt;td&gt;已使用内存&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;mem_fragmentation_ratio&lt;/td&gt;
&lt;td&gt;内存碎片率&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;evicted_keys&lt;/td&gt;
&lt;td&gt;由于最大内存限制被移除的key的数量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;blocked_clients&lt;/td&gt;
&lt;td&gt;由于BLPOP,BRPOP,or BRPOPLPUSH而备阻塞的客户端&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/div&gt;
&lt;h5 id=&#34;基本活动指标：Basic-activity&#34;&gt;&lt;a href=&#34;#基本活动指标：Basic-activity&#34; class=&#34;headerlink&#34; title=&#34;基本活动指标：Basic activity&#34;&gt;&lt;/a&gt;基本活动指标：Basic activity&lt;/h5&gt;&lt;div class=&#34;table-container&#34;&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;connected_clients&lt;/td&gt;
&lt;td&gt;客户端连接数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;conected_laves&lt;/td&gt;
&lt;td&gt;slave数量&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;master_last_io_seconds_ago&lt;/td&gt;
&lt;td&gt;最近一次主从交互之后的秒数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;keyspace&lt;/td&gt;
&lt;td&gt;数据库中的key值总数&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/div&gt;
&lt;h5 id=&#34;持久性指标-Persistence&#34;&gt;&lt;a href=&#34;#持久性指标-Persistence&#34; class=&#34;headerlink&#34; title=&#34;持久性指标: Persistence&#34;&gt;&lt;/a&gt;持久性指标: Persistence&lt;/h5&gt;&lt;div class=&#34;table-container&#34;&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;rdb_last_save_time&lt;/td&gt;
&lt;td&gt;最后一次持久化保存磁盘的时间戳&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;rdb_changes_sice_last_save&lt;/td&gt;
&lt;td&gt;自最后一次持久化以来数据库的更改数&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/div&gt;
&lt;h5 id=&#34;错误指标：Error&#34;&gt;&lt;a href=&#34;#错误指标：Error&#34; class=&#34;headerlink&#34; title=&#34;错误指标：Error&#34;&gt;&lt;/a&gt;错误指标：Error&lt;/h5&gt;&lt;div class=&#34;table-container&#34;&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Name&lt;/th&gt;
&lt;th&gt;Description&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;rejected_connections&lt;/td&gt;
&lt;td&gt;由于达到maxclient限制而被拒绝的连接数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;keyspace_misses&lt;/td&gt;
&lt;td&gt;key值查找失败(没有命中)次数&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;master_link_down_since_seconds&lt;/td&gt;
&lt;td&gt;主从断开的持续时间（以秒为单位)&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/div&gt;
&lt;h5 id=&#34;监控方式&#34;&gt;&lt;a href=&#34;#监控方式&#34; class=&#34;headerlink&#34; title=&#34;监控方式&#34;&gt;&lt;/a&gt;监控方式&lt;/h5&gt;&lt;ul&gt;
&lt;li&gt;redis-benchmark&lt;/li&gt;
&lt;li&gt;redis-stat&lt;/li&gt;
&lt;li&gt;redis-faina&lt;/li&gt;
&lt;li&gt;redislive&lt;/li&gt;
&lt;li&gt;redis-cli&lt;/li&gt;
&lt;li&gt;monitor&lt;/li&gt;
&lt;li&gt;showlog&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;1.get：获取慢查询日志&lt;/p&gt;
&lt;p&gt;2.len：获取慢查询日志条目数&lt;/p&gt;
&lt;p&gt;3.reset：重置慢查询日志&lt;/p&gt;
&lt;p&gt;相关配置：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;slowlog-log-slower-than 1000 # 设置慢查询的时间下线，单位：微秒
slowlog-max-len 100 # 设置慢查询命令对应的日志显示长度，单位：命令数
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;info（可以一次性获取所有的信息，也可以按块获取信息）&lt;/p&gt;
&lt;p&gt;1.server:服务器运行的环境参数&lt;/p&gt;
&lt;p&gt;2.clients:客户端相关信息&lt;/p&gt;
&lt;p&gt;3.memory：服务器运行内存统计数据&lt;/p&gt;
&lt;p&gt;4.persistence：持久化信息&lt;/p&gt;
&lt;p&gt;5.stats：通用统计数据&lt;/p&gt;
&lt;p&gt;6.Replication：主从复制相关信息&lt;/p&gt;
&lt;p&gt;7.CPU：CPU使用情况&lt;/p&gt;
&lt;p&gt;8.cluster：集群信息&lt;/p&gt;
&lt;p&gt;9.Keypass：键值对统计数量信息&lt;/p&gt;
&lt;h5 id=&#34;终端info命令使用&#34;&gt;&lt;a href=&#34;#终端info命令使用&#34; class=&#34;headerlink&#34; title=&#34;终端info命令使用&#34;&gt;&lt;/a&gt;终端info命令使用&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;./redis-cli info 按块获取信息 | grep 需要过滤的参数

./redis-cli info stats | grep ops
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;交互式info命令使用&#34;&gt;&lt;a href=&#34;#交互式info命令使用&#34; class=&#34;headerlink&#34; title=&#34;交互式info命令使用&#34;&gt;&lt;/a&gt;交互式info命令使用&lt;/h5&gt;&lt;pre&gt;&lt;code&gt; #./redis-cli 
&amp;gt; info server
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;性能监控：&#34;&gt;&lt;a href=&#34;#性能监控：&#34; class=&#34;headerlink&#34; title=&#34;性能监控：&#34;&gt;&lt;/a&gt;性能监控：&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;redis-cli info | grep ops # 每秒操作数
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;内存监控&#34;&gt;&lt;a href=&#34;#内存监控&#34; class=&#34;headerlink&#34; title=&#34;内存监控&#34;&gt;&lt;/a&gt;内存监控&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep used | grep human       
used_memory_human:2.99M  # 内存分配器从操作系统分配的内存总量
used_memory_rss_human:8.04M  #操作系统看到的内存占用，top命令看到的内存
used_memory_peak_human:7.77M # redis内存消耗的峰值
used_memory_lua_human:37.00K   # lua脚本引擎占用的内存大小
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;由于BLPOP-BRPOP-or-BRPOPLPUSH而备阻塞的客户端&#34;&gt;&lt;a href=&#34;#由于BLPOP-BRPOP-or-BRPOPLPUSH而备阻塞的客户端&#34; class=&#34;headerlink&#34; title=&#34;由于BLPOP,BRPOP,or BRPOPLPUSH而备阻塞的客户端&#34;&gt;&lt;/a&gt;由于BLPOP,BRPOP,or BRPOPLPUSH而备阻塞的客户端&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep blocked_clients
blocked_clients:0  
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;由于最大内存限制被移除的key的数量&#34;&gt;&lt;a href=&#34;#由于最大内存限制被移除的key的数量&#34; class=&#34;headerlink&#34; title=&#34;由于最大内存限制被移除的key的数量&#34;&gt;&lt;/a&gt;由于最大内存限制被移除的key的数量&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep evicted_keys
evicted_keys:0  #
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;内存碎片率&#34;&gt;&lt;a href=&#34;#内存碎片率&#34; class=&#34;headerlink&#34; title=&#34;内存碎片率&#34;&gt;&lt;/a&gt;内存碎片率&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep mem_fragmentation_ratio
mem_fragmentation_ratio:2.74 
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;已使用内存&#34;&gt;&lt;a href=&#34;#已使用内存&#34; class=&#34;headerlink&#34; title=&#34;已使用内存&#34;&gt;&lt;/a&gt;已使用内存&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep used_memory:
used_memory:3133624  
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;基本活动指标：&#34;&gt;&lt;a href=&#34;#基本活动指标：&#34; class=&#34;headerlink&#34; title=&#34;基本活动指标：&#34;&gt;&lt;/a&gt;基本活动指标：&lt;/h5&gt;&lt;p&gt;redis连接了多少客户端 通过观察其数量可以确认是否存在意料之外的连接。如果发现数量不对劲，就可以使用lcient list指令列出所有的客户端链接地址来确定源头。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep connected_clients
connected_clients:1


[root@CombCloud-2020110836 src]# ./redis-cli info | grep connected
connected_clients:1   # 客户端连接数量
connected_slaves:1   # slave连接数量
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;持久性指标：&#34;&gt;&lt;a href=&#34;#持久性指标：&#34; class=&#34;headerlink&#34; title=&#34;持久性指标：&#34;&gt;&lt;/a&gt;持久性指标：&lt;/h5&gt;&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep rdb_last_save_time
rdb_last_save_time:1591876204  # 最后一次持久化保存磁盘的时间戳
[root@CombCloud-2020110836 src]# ./redis-cli info | grep rdb_changes_since_last_save
rdb_changes_since_last_save:0   # 自最后一次持久化以来数据库的更改数
&lt;/code&gt;&lt;/pre&gt;&lt;h5 id=&#34;错误指标&#34;&gt;&lt;a href=&#34;#错误指标&#34; class=&#34;headerlink&#34; title=&#34;错误指标&#34;&gt;&lt;/a&gt;错误指标&lt;/h5&gt;&lt;p&gt;由于超出最大连接数限制而被拒绝的客户端连接次数，如果这个数字很大，则意味着服务器的最大连接数设置得过低，需要调整maxclients&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep connected_clients
connected_clients:1
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;key值查找失败(没有命中)次数，出现多次可能是被hei ke gongjji&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep keyspace
keyspace_misses:0   
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;主从断开的持续时间（以秒为单位)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep rdb_changes_since_last_save
rdb_changes_since_last_save:0  
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;复制积压缓冲区如果设置得太小，会导致里面的指令被覆盖掉找不到偏移量，从而触发全量同步&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep backlog_size
repl_backlog_size:1048576
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;通过查看sync_partial_err变量的次数来决定是否需要扩大积压缓冲区，它表示主从半同步复制失败的次数&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;[root@CombCloud-2020110836 src]# ./redis-cli info | grep sync_partial_err
sync_partial_err:1
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;redis性能测试命令&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;./redis-benchmark -c 100 -n 5000
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/gu1ZLXlR9ud4wnssYMVkMw&#34;&gt;https://mp.weixin.qq.com/s/gu1ZLXlR9ud4wnssYMVkMw&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;当我们的ES集群搭建完成以后，我怎么能看到集群中各个节点状态以及主节点和健康情况呢，如下讲解使用curl命令来与ES集群进行交互、分别有查询主节点情况、集群状态、以及创建索引查看索引、查看分片以及对ES集群进行查询请求等操作。&lt;br&gt;&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;br&gt;CURL语法讲解&lt;/p&gt;
&lt;p&gt;RESTful API:&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;    curl  -X&amp;lt;VERB&amp;gt; &amp;#39;&amp;lt;PROTOCOL&amp;gt;://&amp;lt;HOST&amp;gt;:&amp;lt;PORT&amp;gt;/&amp;lt;PATH&amp;gt;?&amp;lt;QUERY_STRING&amp;gt;&amp;#39; -d &amp;#39;&amp;lt;BODY&amp;gt;&amp;#39;
    -X：指定请求方式

    &amp;lt;VERB&amp;gt;：GET,POST,PUT,DELETE   一般请求为GET、提交变更为POST、上传文件为PUT、删除操作为DELETE

    &amp;lt;PROTOCOL&amp;gt;：协议，一般为HTTP协议

    &amp;lt;HOST&amp;gt;：主机，可为主机的IP地址或Hostname

    &amp;lt;PORT&amp;gt;：主机端口

    &amp;lt;PATH&amp;gt;：路径，主机端口后的路径，如下几个路径：/_cat, /_search, /_cluster   /_cat路径覆盖了大多数的信息内容,/_search为搜索所有的索引和文档类型

    &amp;lt;QUERY_STRING&amp;gt;：查询字符串匹配规则

    -d：指定主体内容

    &amp;lt;BODY&amp;gt;：json格式的请求主体
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Elasticseearch基本查询语句&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;    //查看_cat支持的信息
    kibana: GET /_cat
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat&amp;#39;        

    //查看主节点信息
    kibana: GET /_cat/master?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/master?v&amp;#39;        

    //查看集群所有节点
    kibana: GET /_cat/nodes?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/nodes?v&amp;#39;        

    //查看所有索引信息
    kibana: GET /_cat/indices?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/indices?v&amp;#39;        

    //查看单个索引信息
    kibana: GET /_cat/indices/movies?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/indices/movies?v&amp;#39;        

    //查看所有分片信息
    kibana: GET /_cat/shards?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/shards?v&amp;#39;        

    //查看单个索引分片信息
    kibana: GET /_cat/shards/movies?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/shards/movies?v&amp;#39;        

    //查看集群健康状态
    kibana: GET /_cat/health?v
    kibana: GET _cluster/health
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/health?v&amp;#39;
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cluster/health?pretty&amp;#39;        

    //查看插件
    kibana: GET /_cat/plugins?v
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/plugins?v&amp;#39;        

    //查看所有索引文档总数
    kibana: GET _all/_count
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_all/_count?pretty&amp;#39;        

    //查看指定索引文档总数
    kibana: GET movies/_count
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/movies/_count?pretty&amp;#39;        

    //查看所有模板
    kibana: GET _cat/templates
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/templates?v&amp;#39;        

    //查看状态为绿的索引
    kibana: GET /_cat/indices?v&amp;amp;health=green
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/indices?v&amp;amp;health=green&amp;#39;        

    //查看movies索引元数据
    kibana: GET movies
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/movies?pretty&amp;#39;        

    //按照文档数量排序索引
    kibana: GET _cat/indices?v&amp;amp;s=docs.count:desc
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/indices?v&amp;amp;s=docs.count:desc&amp;#39;        

    //查看各个索引占用内存大小并进行排序
    kibana: 
    bash: curl -XGET -u elastic:26tBktGolYCyZD2pPISW &amp;#39;http://192.168.31.215:9201/_cat/indices?v&amp;amp;h=i,tm&amp;amp;s=tm:desc&amp;#39;
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;Elasticsearch CURD语法&lt;/p&gt;
&lt;div class=&#34;table-container&#34;&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;CURD&lt;/th&gt;
&lt;th&gt;请求方式&lt;/th&gt;
&lt;th&gt;主体&lt;/th&gt;
&lt;th&gt;说明&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Create&lt;/td&gt;
&lt;td&gt;PUT&lt;/td&gt;
&lt;td&gt;/index/_create/id&lt;/td&gt;
&lt;td&gt;指定Document ID，创建文档，如果ID已存在，则失败&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Create&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_create/id&lt;/td&gt;
&lt;td&gt;指定Document ID，创建文档，如果ID已存在，则失败&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Create&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_doc&lt;/td&gt;
&lt;td&gt;自动生成ID，不会重复，重复提交则创建多个文档，文档版本都为1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Index&lt;/td&gt;
&lt;td&gt;PUT&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;如果ID不存在,则创建新的文档,如果ID存在,则删除现有文档后创建新的文档,版本+1,ID相同&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Index&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;如果ID不存在,则创建新的文档,如果ID存在,则删除现有文档后创建新的文档,版本+1,ID相同&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Read&lt;/td&gt;
&lt;td&gt;GET&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;查看Document ID为1的文档&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Update&lt;/td&gt;
&lt;td&gt;POST&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;文档必须存在,否则更新失败,只能增量修改字段,不能减少字段,字段值可以随意修改,版本加1&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;/index/_doc/id&lt;/td&gt;
&lt;td&gt;文档必须存在,否则删除返回”not_found”&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;Delete&lt;/td&gt;
&lt;td&gt;/index&lt;/td&gt;
&lt;td&gt;删除索引，索引内的文档也会被随之而删除,要删除的索引必须存在,否则返回 “404”&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;/div&gt;
&lt;p&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/qZq_EV9q1LUUzOZeTzhA-g&#34;&gt;https://mp.weixin.qq.com/s/qZq_EV9q1LUUzOZeTzhA-g&lt;/a&gt;&lt;/p&gt;

 &lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://kubernetes.io&#34;&gt;Kubernetes&lt;/a&gt;  容器编排平台&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/kubernetes/kubernetes&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Kubernetes! 说起云原生应用，怎么能不提 Kubernetes 呢？Google 发明的 Kubernetes 无疑是最著名的基于容器的应用程序的容器编排平台，而且它还是一个开源工具。&lt;/p&gt;
&lt;p&gt;什么是容器编排平台？通常，一个容器引擎本身可以管理几个容器。但是，当你谈论数千个容器和数百个服务时，管理这些容器变得非常复杂。这就是容器编排引擎的用武之地。容器编排引擎通过自动化容器的部署、管理、网络和可用性来帮助管理大量的容器。&lt;/p&gt;
&lt;p&gt;Docker Swarm 和 Mesosphere Marathon 也是容器编排引擎，但是可以肯定地说，Kubernetes 已经赢得了这场比赛（至少现在是这样）。Kubernetes 还催生了像 OKD 这样的容器即服务（CaaS）平台，它是 Kubernetes 的 Origin 社区发行版，并成了 Red Hat OpenShift 的一部分。&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://prometheus.io&#34;&gt;Prometheus&lt;/a&gt;    系统和服务监控工具&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/prometheus/prometheus&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Prometheus 是 2012 年在 SoundCloud 上构建的一个开源的系统监控和告警工具。之后，许多公司和组织都采用了 Prometheus，并且该项目拥有非常活跃的开发者和用户群体。现在，它已经成为一个独立的开源项目，独立于公司之外进行维护。&lt;br&gt;理解 Prometheus 的最简单方法是可视化一个生产系统，该系统需要 24（小时）x 365（天）都可以正常运行。没有哪个系统是完美的，也有减少故障的技术（称为容错系统），但是，如果出现问题，最重要的是尽快发现问题。这就是像 Prometheus 这样的监控工具的用武之地。Prometheus 不仅仅是一个容器监控工具，但它在云原生应用公司中最受欢迎。此外，其他开源监视工具，包括 Grafana，都借助了 Prometheus。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://www.envoyproxy.io&#34;&gt;Envoy&lt;/a&gt;        边缘和服务代理&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/envoyproxy/envoy&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Envoy（或 Envoy 代理）是专为云原生应用设计的开源的边缘代理和服务代理。由 Lyft 创建的 Envoy 是为单一服务和应用而设计的高性能的 C++ 开发的分布式代理，同时也是为由大量微服务组成的服务网格架构而设计的通信总线和通用数据平面。Envoy 建立在 Nginx、HAProxy、硬件负载均衡器和云负载均衡器等解决方案的基础上，Envoy 与每个应用相伴（并行）运行，并通过提供平台无关的方式提供通用特性来抽象网络。&lt;/p&gt;
&lt;p&gt;当基础设施中的所有服务流量都经过 Envoy 网格时，很容易就可以通过一致的可观测性来可视化问题域，调整整体性能，并在单个位置添加基础功能。基本上，Envoy 代理是一个可帮助组织为生产环境构建容错系统的服务网格工具。&lt;/p&gt;
&lt;p&gt;服务网格应用有很多替代方案，例如 Uber 的 Linkerd（下面会讨论）和 Istio。Istio 通过将其部署为 Sidecar 并利用了 Mixer 的配置模型，实现了对 Envoy 的扩展。Envoy 的显著特性有：&lt;/p&gt;
&lt;p&gt;◈ 包括所有的“入场筹码(table stakes)（LCTT 译注：引申为基础必备特性）”特性（与 Istio 这样的控制平面组合时）&lt;/p&gt;
&lt;p&gt;◈ 带载运行时 99% 数据可达到低延时&lt;/p&gt;
&lt;p&gt;◈ 可以作为核心的 L3/L4 过滤器，提供了开箱即用的 L7 过滤器&lt;/p&gt;
&lt;p&gt;◈ 支持 gRPC 和 HTTP/2（上行/下行）&lt;/p&gt;
&lt;p&gt;◈ 由 API 驱动，并支持动态配置和热重载&lt;/p&gt;
&lt;p&gt;◈ 重点关注指标收集、跟踪和整体可监测性&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://coreos.com/rkt/docs/latest&#34;&gt;rkt&lt;/a&gt;        Pod 原生的容器引擎&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/rkt/rkt&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;rkt, 读作“rocket”，是一个 Pod 原生的容器引擎。它有一个命令行接口用来在 Linux 上运行容器。从某种意义上讲，它和其他容器如 Podman、Docker 和 CRI-O 相似。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://www.jaegertracing.io&#34;&gt;Jaeger&lt;/a&gt;        分布式跟踪系统&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/jaegertracing/jaeger&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Jaeger 是一个开源的端到端的分布式追踪系统，适用于云端应用。在某种程度上，它是像 Prometheus 这样的监控解决方案。但它有所不同，因为其使用场景有所扩展：&lt;/p&gt;
&lt;p&gt;◈ 分布式事务监控&lt;/p&gt;
&lt;p&gt;◈ 性能和延时优化&lt;/p&gt;
&lt;p&gt;◈ 根因分析&lt;/p&gt;
&lt;p&gt;◈ 服务依赖性分析&lt;/p&gt;
&lt;p&gt;◈ 分布式上下文传播&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://linkerd.io&#34;&gt;Linkerd&lt;/a&gt;    透明服务网格&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/linkerd/linkerd&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;像创建 Envoy 代理的 Lyft 一样，Uber 开发了 Linkerd 开源解决方案用于生产级的服务维护。在某些方面，Linkerd 就像 Envoy 一样，因为两者都是服务网格工具，旨在提供平台级的可观测性、可靠性和安全性，而无需进行配置或代码更改。&lt;/p&gt;
&lt;p&gt;但是，两者之间存在一些细微的差异。尽管 Envoy 和 Linkerd 充当代理并可以通过所连接的服务进行上报，但是 Envoy 并不像 Linkerd 那样被设计为 Kubernetes Ingress 控制器。Linkerd 的显著特点包括：&lt;/p&gt;
&lt;p&gt;◈ 支持多种平台（Docker、Kubernetes、DC/OS、Amazon ECS 或任何独立的机器）&lt;/p&gt;
&lt;p&gt;◈ 内置服务发现抽象，可以将多个系统联合在一起&lt;/p&gt;
&lt;p&gt;◈ 支持 gRPC、HTTP/2 和 HTTP/1.x请 求和所有的 TCP 流量&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://helm.sh&#34;&gt;Helm&lt;/a&gt;        Kubernetes 包管理器&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/helm/helm&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Helm 基本上就是 Kubernetes 的包管理器。如果你使用过 Apache Maven、Maven Nexus 或类似的服务，你就会理解 Helm 的作用。Helm 可帮助你管理 Kubernetes 应用程序。它使用“Helm Chart”来定义、安装和升级最复杂的 Kubernetes 应用程序。Helm 并不是实现此功能的唯一方法；另一个流行的概念是 Kubernetes Operators，它被 Red Hat OpenShift 4 所使用。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://etcd.io&#34;&gt;Etcd&lt;/a&gt;        分布式键值存储&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/etcd-io/etcd&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Etcd 是一个分布式的、可靠的键值存储，用于存储分布式系统中最关键的数据。其主要特性有：&lt;/p&gt;
&lt;p&gt;◈ 定义明确的、面向用户的 API（gRPC）&lt;/p&gt;
&lt;p&gt;◈ 自动 TLS，可选的客户端证书验证&lt;/p&gt;
&lt;p&gt;◈ 速度（可达每秒 10,000 次写入）&lt;/p&gt;
&lt;p&gt;◈ 可靠性（使用 Raft 实现分布式）&lt;/p&gt;
&lt;p&gt;Etcd 是 Kubernetes 和许多其他技术的默认的内置数据存储方案。也就是说，它很少独立运行或作为单独的服务运行；相反，它以集成到 Kubernetes、OKD/OpenShift 或其他服务中的形式来运作。还有一个 etcd Operator 可以用来管理其生命周期并解锁其 API 管理功能&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/cri-o/cri-o/blob/master/awesome.md&#34;&gt;CRI-O&lt;/a&gt;    专门用于 Kubernetes 的轻量级运行时环境&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&lt;a href=&#34;https://github.com/cri-o/cri-o&#34;&gt;github&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;CRI-O 是 Kubernetes 运行时接口的 OCI 兼容实现。CRI-O 用于各种功能，包括：&lt;/p&gt;
&lt;p&gt;◈ 使用 runc（或遵从 OCI 运行时规范的任何实现）和 OCI 运行时工具运行&lt;/p&gt;
&lt;p&gt;◈ 使用容器/镜像进行镜像管理&lt;/p&gt;
&lt;p&gt;◈ 使用容器/存储来存储和管理镜像层&lt;/p&gt;
&lt;p&gt;◈ 通过容器网络接口（CNI）来提供网络支持&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;原文章地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/t4bXqZLtvm_Xc1RiPq7rEw&#34;&gt;https://mp.weixin.qq.com/s/t4bXqZLtvm_Xc1RiPq7rEw&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;来源：知乎，作者：大狐狸&lt;/p&gt;
&lt;p&gt;链接：&lt;a href=&#34;https://www.zhihu.com/question/36426051/answer/76031743&#34;&gt;https://www.zhihu.com/question/36426051/answer/76031743&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;1.重构是程序员的主力技能。&lt;/p&gt;
&lt;p&gt;2.工作日志能提升脑容量。&lt;/p&gt;
&lt;p&gt;3.先用profiler调查，才有脸谈优化。&lt;/p&gt;
&lt;p&gt;4.注释贵精不贵多。杜绝大姨妈般的“例注”。漫山遍野的碎碎念注释，实际就是背景噪音。&lt;/p&gt;
&lt;p&gt;5.普通程序员+google=超级程序员。&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;p&gt;6.单元测试总是合算的。&lt;/p&gt;
&lt;p&gt;7.不要先写框架再写实现。最好反过来，从原型中提炼框架。&lt;/p&gt;
&lt;p&gt;8.代码结构清晰，其它问题都不算事儿。&lt;/p&gt;
&lt;p&gt;9.好的项目作风硬派，一键测试，一键发布，一键部署；烂的项目生性猥琐，口口相传，不立文字，神神秘秘。&lt;/p&gt;
&lt;p&gt;10.编码不要畏惧变化，要拥抱变化。&lt;/p&gt;
&lt;p&gt;11.常充电。程序员只有一种死法：土死的。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;编程之事，隔离是方向，起名是关键，测试是主角，调试是补充，版本控制是后悔药。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;一行代码一个兵。形成建制才能有战斗力。单位规模不宜过大，千人班，万人排易成万人坑。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;重构/优化/修复Bug，同时只能作一件。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;简单模块注意封装，复杂模块注意分层。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;人脑性能有限，整洁胜于杂乱。读不懂的代码，尝试整理下格式；不好用的接口，尝试重新封装下。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;迭代速度决定工作强度。想多快好省，就从简化开发流程，加快迭代速度开始。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;忘掉优化写代码，过早优化等同恶意破坏；忘掉代码作优化，优化要基于性能测试，而不是纠结于字里行间。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;最好的工具是纸笔；其次好的是markdown。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;leader问任务时间，若答不上来，可能是任务拆分还不够细。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;宁可多算一周，不可少估一天。过于“乐观”容易让boss受惊吓。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;最有用的语言是English。其次的可能是Python。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;百闻不如一见。画出结果，一目了然。调试耗时将大大缩短。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;资源、代码应一道受版本管理。资源匹配错误远比代码匹配错误更难排查。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;不要基于想象开发， 要基于原型开发。原型的价值是快速验证想法，帮大家节省时间。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;序列化首选明文文本 。诸如二进制、混淆、加密、压缩等等有需要时再加。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;编译器永远比你懂微观优化。只能向它不擅长的方向努力。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;不要定过大、过远、过细的计划。即使定了也没有用。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;至少半数时间将花在集成上。时间，时间，时间总是不够。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;与主流意见/方法/风格/习惯相悖时，先检讨自己最可靠。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;出现bug主动查，不管是不是你的。这能让你业务能力猛涨、个人形象飙升; 如果你的bug被别人揪出来…..呵呵，那你会很被动～≧﹏≦&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;不知怎么选技术书时就挑薄的。起码不会太贵，且你能看完。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;git是最棒的。简单，可靠，免费。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;仅对“可预测的非理性”抛断言。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;Log要写时间与分类。并且要能重定向输出。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;注释是稍差的文档。更好的是清晰的命名。让代码讲自己的故事。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;造轮子是很好的锻炼方法。前提是你见过别的轮子。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;code review最好以小组/结对的形式。对业务有一定了解，建议会更有价值（但不绝对）。而且不会成为负担。管理员个人review则很容易成team的瓶颈。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;提问前先做调研。问不到点上既被鄙视，又浪费自己的时间。&lt;/li&gt;
&lt;/ol&gt;
&lt;ol&gt;
&lt;li&gt;永远别小看程序媛(╯3╰)&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;一、缘起&lt;/p&gt;
&lt;p&gt;1.1、鸿蒙&lt;/p&gt;
&lt;p&gt;在上古时期，天地初开，一群称之为 “运维” 的人们每天在一种叫作 “服务器” 的神秘盒子中创造属于他们的世界；他们在这个世界中每日劳作，一遍又一遍的写入他们的历史，比如搭建一个 nginx、布署一个 java web 应用…&lt;/p&gt;
&lt;p&gt;大多数人其实并没有那么聪明，他们所 “创造” 的事实上可能是有人已经创造过的东西，他们可能每天都在做着重复的劳动；久而久之，一些人厌倦了、疲惫了…又过了一段时间，一些功力深厚的老前辈创造了一些批量布署工具来帮助人们做一些重复性的劳动，这些工具被起名为 “Asible”、”Chef”、”Puppet” 等等…&lt;br&gt;&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;br&gt;而随着时代的发展，”世界” 变得越来越复杂，运维们需要处理的事情越来越多，比如各种网络、磁盘环境的隔离，各种应用服务的高可用…在时代的洪流下，运维们急需要一种简单高效的布署工具，既能有一定的隔离性，又能方便使用，并且最大程度降低重复劳动来提升效率。&lt;/p&gt;
&lt;p&gt;1.2、创世&lt;/p&gt;
&lt;p&gt;在时代洪流的冲击下，一位名为 “Solomon Hykes” 的人异军突起，他创造了一个称之为 Docker 的工具，Docker 被创造以后就以灭世之威向运维们展示了它的强大；一个战斗力只有 5 的运维只需要学习 Docker 很短时间就可以完成资深运维们才能完成的事情，在某些情况下以前需要 1 天才能完成的工作使用 Docker 后几分钟就可以完成；此时运维们已经意识到 “新的时代” 开启了，接下来 Docker 开源并被整个运维界人们使用，Docker 也不断地完善增加各种各样的功能，此后世界正式进入 “容器纪元”。&lt;/p&gt;
&lt;p&gt;二、纷争&lt;/p&gt;
&lt;p&gt;2.1、发展&lt;/p&gt;
&lt;p&gt;随着 Docker 的日益成熟，一些人开始在 Docker 之上创造更加强大的工具，一些人开始在 Docker 之下为其提供更稳定的运行环境…&lt;/p&gt;
&lt;p&gt;其中一个叫作 Google 的公司在 Docker 之上创建了名为 “Kuberentes” 的工具，Kubernetes 操纵 Docker 完成更加复杂的任务；Kubernetes 的出现更加印证了 Docker 的强大，以及 “容器纪元” 的发展正确性。&lt;/p&gt;
&lt;p&gt;2.2、野心&lt;/p&gt;
&lt;p&gt;当然这是一个充满利益的世界，Google 公司创造 Kubernetes 是可以为他们带来利益的，比如他们可以让 Kubernetes 深度适配他们的云平台，以此来增加云平台的销量等；此时 Docker 创始人也成立了一个公司，提供 Docker 的付费服务以及深度定制等；不过值得一提的是 Docker 公司提供的付费服务始终没有 Kubernetes 为 Google 公司带来的利益高，所以在利益的驱使下，Docker 公司开始动起了歪心思: 创造一个 Kubernetes 的替代品，利用用户粘度复制 Kubernetes 的成功，从 Google 嘴里抢下这块蛋糕！此时 Docker 公司只想把蛋糕抢过来，但是他们根本没有在意到暗中一群人创造了一个叫 “rkt” 的东西也在妄图夺走他们嘴里的蛋糕。&lt;/p&gt;
&lt;p&gt;2.3、冲突&lt;/p&gt;
&lt;p&gt;在一段时间的沉默后，Docker 公司又创造了 “Swarm” 这个工具，妄图夺走 Google 公司利用 Kubernetes 赢来的蛋糕；当然，Google 这个公司极其庞大，人数众多，而且在这个社会有很大的影响地位…&lt;/p&gt;
&lt;p&gt;终于，巨人苏醒了，Google 联合了 Redhat、Microsoft、IBM、Intel、Cisco 等公司决定对这个爱动歪脑筋的 Docker 公司进行制裁；当然制裁的手段不能过于暴力，那样会让别人落下把柄，成为别人的笑料，被人所不耻；最总他们决定制订规范，成立组织，明确规定 Docker 的角色，以及它应当拥有的能力，这些规范包括但不限于 CRI、CNI 等；自此之后各大公司宣布他们容器相关的工具只兼容 CRI 等相关标准，无论是 Docker 还是 rkt 等工具，只要实现了这些标准，就可以配合这些容器工具进行使用。&lt;/p&gt;
&lt;p&gt;三、成败&lt;/p&gt;
&lt;p&gt;自此之后，Docker 跌下神坛，各路大神纷纷创造满足 CRI 等规范的工具用来取代 Docker，Docker 丢失了往日一家独大的场面，最终为了顺应时代发展，拆分自己成为模块化组件；这些模块化组件被放置在 mobyproject 中方便其他人重复利用。&lt;/p&gt;
&lt;p&gt;时至今日，虽然 Docker 已经不负以前，但是仍然是容器化首选工具，因为 Docker 是一个完整的产品，它可以提供除了满足 CRI 等标准以外更加方便的功能；但是制裁并非没有结果，Google 公司借此创造了 cri-o 用来满足 CRI 标准，其他公司也相应创建了对应的 CRI 实现；为了进一步分化 Docker 势力，一个叫作 Podman 的工具被创建，它以 cri-o 为基础，兼容大部份 Docker 命令的方式开始抢夺 Dcoker 用户；到目前为止 Podman 已经可以在大部份功能上替代 Docker。&lt;/p&gt;
&lt;p&gt;原文地址：&lt;a href=&#34;https://mritd.me/2019/06/26/podman-history-of-container&#34;&gt;https://mritd.me/2019/06/26/podman-history-of-container&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;设置时区&lt;br&gt;date_default_timezone_set(“Asia/Shanghai”);&lt;br&gt;date_default_timezone_set(‘PRC’);//这两种方法效果相同&lt;br&gt;1&lt;br&gt;2&lt;br&gt;时间戳转日期，可以用date(‘Y-m-s h:i:s’, 具体时间戳来实现)&lt;br&gt;日期转换时间戳，用strtotime(“date()”).&lt;br&gt;&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;br&gt;时间戳格式&lt;br&gt;    //获取今日开始时间戳和结束时间戳&lt;br&gt;    $beginToday=mktime(0,0,0,date(‘m’),date(‘d’),date(‘Y’));&lt;br&gt;    $endToday=mktime(0,0,0,date(‘m’),date(‘d’)+1,date(‘Y’))-1;  &lt;/p&gt;
&lt;pre&gt;&lt;code&gt;//获取昨日起始时间戳和结束时间戳  
$beginYesterday=mktime(0,0,0,date(&amp;#39;m&amp;#39;),date(&amp;#39;d&amp;#39;)-1,date(&amp;#39;Y&amp;#39;));  
$endYesterday=mktime(0,0,0,date(&amp;#39;m&amp;#39;),date(&amp;#39;d&amp;#39;),date(&amp;#39;Y&amp;#39;))-1;  

//获取本周起始时间戳和结束时间戳   
$beginThisweek = mktime(0,0,0,date(&amp;#39;m&amp;#39;),date(&amp;#39;d&amp;#39;)-date(&amp;#39;w&amp;#39;)+1,date(&amp;#39;y&amp;#39;));  
$endThisweek=time();  

//获取上周起始时间戳和结束时间戳  
$beginLastweek=mktime(0,0,0,date(&amp;#39;m&amp;#39;),date(&amp;#39;d&amp;#39;)-date(&amp;#39;w&amp;#39;)+1-7,date(&amp;#39;Y&amp;#39;));  
$endLastweek=mktime(23,59,59,date(&amp;#39;m&amp;#39;),date(&amp;#39;d&amp;#39;)-date(&amp;#39;w&amp;#39;)+7-7,date(&amp;#39;Y&amp;#39;));  

//获取本月起始时间戳和结束时间戳  
$beginThismonth=mktime(0,0,0,date(&amp;#39;m&amp;#39;),1,date(&amp;#39;Y&amp;#39;));  
$endThismonth=mktime(23,59,59,date(&amp;#39;m&amp;#39;),date(&amp;#39;t&amp;#39;),date(&amp;#39;Y&amp;#39;));  

 //上个月的起始时间:  
$begin_time = strtotime(date(&amp;#39;Y-m-01 00:00:00&amp;#39;,strtotime(&amp;#39;-1 month&amp;#39;)));  
$end_time = strtotime(date(&amp;quot;Y-m-d 23:59:59&amp;quot;, strtotime(-date(&amp;#39;d&amp;#39;).&amp;#39;day&amp;#39;)));  

$begin_year = strtotime(date(&amp;quot;Y&amp;quot;,time()).&amp;quot;-1&amp;quot;.&amp;quot;-1&amp;quot;); //本年开始  
$end_year = strtotime(date(&amp;quot;Y&amp;quot;,time()).&amp;quot;-12&amp;quot;.&amp;quot;-31&amp;quot;); //本年结束  

//现在的时间到第二天凌晨相差的时间戳  
$time = (strtotime(date(&amp;#39;Y-m-d&amp;#39;))+3600*24) - time() ; 
&lt;/code&gt;&lt;/pre&gt;&lt;p&gt;日期格式&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#x27;&amp;lt;br&amp;gt;上周起始时间:&amp;lt;br&amp;gt;&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+1-7,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+7-7,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#x27;&amp;lt;br&amp;gt;本周起始时间:&amp;lt;br&amp;gt;&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+1,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;),date(&amp;quot;d&amp;quot;)-date(&amp;quot;w&amp;quot;)+7,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#x27;&amp;lt;br&amp;gt;上月起始时间:&amp;lt;br&amp;gt;&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;)-1,1,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;) ,0,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo &amp;#x27;&amp;lt;br&amp;gt;本月起始时间:&amp;lt;br&amp;gt;&amp;#x27;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(0, 0 , 0,date(&amp;quot;m&amp;quot;),1,date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(&amp;quot;Y-m-d H:i:s&amp;quot;,mktime(23,59,59,date(&amp;quot;m&amp;quot;),date(&amp;quot;t&amp;quot;),date(&amp;quot;Y&amp;quot;))),&amp;quot;\n&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//本年起始&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(‘Y-01-01’); &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;//结束日期 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;echo date(‘Y-12-31’);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;原文链接：&lt;a href=&#34;https://blog.csdn.net/qq_40018938/article/details/81031414&#34;&gt;https://blog.csdn.net/qq_40018938/article/details/81031414&lt;/a&gt;&lt;/p&gt;

 &lt;h2 id=&#34;1&#34;&gt;&lt;a href=&#34;#1&#34; class=&#34;headerlink&#34; title=&#34;1&#34;&gt;&lt;/a&gt;1&lt;/h2&gt;&lt;p&gt;首先问大家两个问题：&lt;/p&gt;
&lt;p&gt;1）为什么爬树和种田最厉害的人，高考不能加分，而作文写得好的蒋方舟、打球打得好的科比和跨栏跑得快的刘翔，大学抢着要？&lt;/p&gt;
&lt;p&gt;2）为什么犹太人在历史上两千多年都受尽压迫，近现代却能牛人辈出？&lt;/p&gt;
&lt;p&gt;这两个问题不慌回答，看完全文，你自然明白。              &lt;/p&gt;
&lt;p&gt;现在我们先说本文的主旨：你之所以在城市里过得那么艰辛，成功离你那么遥不可及，可能是因为你还在用农业社会的思维和习惯去生活、工作、社交、投资，你没有适应工商业时代的社会需要。&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;在城市里上过学，或已经在城市生活很久，甚至在城里长大，并不必然是个城里人了。只要从思维和行为习惯上，你还没有摆脱长期农业社会在你身上的烙印，你就还是一个乡下土人。&lt;/p&gt;
&lt;p&gt;你的土味，会杀死机遇，阻止成功，把你死死拖在失败的泥潭里。&lt;/p&gt;
&lt;p&gt;市场经济中，只有适应社会需要的人，才能赚到钱。不适应社会需要的，只能沦为屌丝。&lt;/p&gt;
&lt;p&gt;也就是说，只有去掉土味，你才可能成功。&lt;/p&gt;
&lt;h2 id=&#34;2&#34;&gt;&lt;a href=&#34;#2&#34; class=&#34;headerlink&#34; title=&#34;2&#34;&gt;&lt;/a&gt;2&lt;/h2&gt;&lt;p&gt;王小波的杂文《打工经历》里曾经说到过一件事。&lt;/p&gt;
&lt;p&gt;他在美国留学的时候，因为缺钱，和同学老曹揽了一个给中餐馆装修房子的活。那活本来轮不到他俩，因为老板特别抠门，舍不得请正规装修队，就让他俩来干。结果，俩人出尽了洋相。&lt;/p&gt;
&lt;p&gt;文章写得非常幽默。我把主要内容分享如下：&lt;/p&gt;
&lt;p&gt;“以前，我知道美国的科技发达、商业也发达，但我还不知道，美国还是各种手艺人的国家。我们打工的那条街上就有一大窝，什么电工、管子工、木工等等，还有包揽装修工程的小包工头儿；一听见我们开了工，就都跑来看。先看我们抡大锤、打钎子，面露微笑，然后就跑到后面去找老板，说：你请的这两个宝贝要是在本世纪内能把这餐馆装修完，我输你一百块钱。我脸上着实挂不住，真想扔了钎子不干。但老曹从牙缝里啐口吐沫说：不理他！这个世纪干不完，还有下个世纪，反正赤佬要给我们工钱……“&lt;/p&gt;
&lt;p&gt;王小波和老曹都没干过装修，就是卖力气。老曹提出要买各种工具，但抠门老板舍不得，认为他俩想揩油。&lt;/p&gt;
&lt;p&gt;“等把地面打掉以后，我们在这条街上赢得了一定程度的尊敬。顺便说一句，打下来的水泥块是我一块块抱出去，扔到垃圾箱里，老板连个手推车都舍不得租。他觉得已经出了人工钱，再租工具就是吃了亏。那些美国的工匠路过时，总来聊聊天，对我们的苦干精神深表钦佩。但是他们说，活可不是你们俩这种干法。说实在的，他们都想揽这个装修工程，只是价钱谈不拢。下一步是把旧有的隔断墙拆了。我觉得这很简单，挥起大锤就砸——才砸了一下，就被老板喝止。他说这会把墙里的木料砸坏。隔断墙里能有什么木料，不过是些零零碎碎的破烂木头。但老板说，要用它来造地板。于是，我们就一根根把这些烂木头上的钉子起出来。美国人见了问我们在干什么，我如实一说，对方捂住肚子往地下一蹲，笑得就地打起滚来。这回连老曹脸上都挂不住了，直怪我太多嘴……“&lt;/p&gt;
&lt;p&gt;后面，美国的工人都来围观他俩怎么干活。由于活实在太烂，对方好奇问他俩是干啥的。王小波之前是大学老师，老曹之前在沪东船厂当工程师，为了不给老东家丢脸，王小波厚着脸皮说两人都是艺术家。美国工人说：“早看出来你们是艺术家了……工人没有像你们这样干活的。“&lt;/p&gt;
&lt;p&gt;虽然又羞又愤，但因为是在是穷，他俩还是坚持下来。&lt;/p&gt;
&lt;p&gt;“我们给赤佬老板干了一个多月，也赚了他几百块钱的工钱，那个餐馆还是不像餐馆，也不像是冷库，而是像个破烂摊。转眼间夏去秋来，我们也该回去上学了。那老板的脸色越来越难看，天天催我们加班。催也没有用，手里拿着手锤铁棍，拼了命也是干不出活来的。“&lt;/p&gt;
&lt;p&gt;抠门老板实在是受不了了，直好把他俩开了，另请装修队。老曹倒很知耻，一定要弄清楚老美的工人是怎么干活的。&lt;/p&gt;
&lt;p&gt;“美国包工头接下了这个工程，马上把它分了出去，分给电工、木工、管子工，今天上午是你的，下午是他的，后天是我的，等等。几个电话打出去，就有人来送工具，满满当当一卡车。这些工具不要说我，连老曹都没见过。除了电锯电刨，居然还有用电瓶的铲车，可以在室内开动，三下五除二，就把我们留下的破烂从室内推了出去。电工上了电动升降台，在天花板上下电线，底下木工就在装配地板，手法纯熟之极。虽然是用现成的构件，也得承认人家干活真是太快了。装好以后电刨子一跑，贼亮；干完了马上走人，运走机械，新的工人和机械马上开进来……转眼之间，饭馆就有个样儿了……”&lt;/p&gt;
&lt;p&gt;最后王小波用下面这句话做了结尾：&lt;/p&gt;
&lt;p&gt;“我和老曹看了一会儿，就灰溜溜地走开了。这是因为我们都当过工人，知道怎么工作才有尊严。”&lt;/p&gt;
&lt;p&gt;我年轻时看这文，只知道挺好玩。后来才想明白，这其实是以小见大，深刻反映了两种文明的对撞和其中一种对另一种的绝对碾压。&lt;/p&gt;
&lt;p&gt;在该文里，王小波、老曹、抠门老板代表了农业文明下成长起来的，充满了乡土气息的乡下土人，美国工人代表了在现代工业文明下成长起来的现代人。在这次对撞中，农业文明被工业文明打击得体无完肤，毫无尊严——而这，又何尝不是工业革命以来，所有工业文明国家对农业文明国家全方位碾压的一个缩影。&lt;/p&gt;
&lt;h2 id=&#34;3&#34;&gt;&lt;a href=&#34;#3&#34; class=&#34;headerlink&#34; title=&#34;3&#34;&gt;&lt;/a&gt;3&lt;/h2&gt;&lt;p&gt;以色列学者尤瓦尔·赫拉利在他风靡全球的现象级畅销书《人类简史》中提出了一个观点，人类的生理结构和生活、思维、社交习惯，其实是为了适应数百万年的采集生活而形成的。这些习惯，到现在还在影响着我们。&lt;/p&gt;
&lt;p&gt;从这一推论出发，人类社会这几千年来不同的生活方式，也在不同的人群中形成了不同的思维和行为模式。80年代中国人曾经反思“黄土文明“，希望拥抱”海洋文明“。这种反思虽然后来走过了头，走向了对中华民族整个的否定，但其提出的一些观点是值得思考的。中国人的黄土思维，在现代化的冲击下，有些地方需要作出改变。&lt;/p&gt;
&lt;p&gt;托马斯·索威尔的名著《美国种族简史》分析了犹太人在现代社会的崛起。&lt;/p&gt;
&lt;p&gt;在长达2千年的时间里，犹太人是没有国家，没有土地的一个可怜的流浪民族。他们在任何一个地方，都处于被压榨、被排挤、被欺负、被诋毁、被防范的状态。由于长期没有土地，犹太人只好从事商业、手工业、中介、放贷收利息的古典金融业等行业。&lt;/p&gt;
&lt;p&gt;但是在工业革命之后，长期从事工商业的犹太人，迅速地适应了现代社会。不管是在欧洲还是新大陆，犹太人都飞速崛起，在商界、政界、知识界获得了举世瞩目的成绩。现代知名的世界级学者，很多是犹太人；金融业，犹太人掌控了华尔街，可以在全球呼风唤雨；律师、咨询等专业服务业，犹太人建立了非常好的口碑；在美国人中，犹太人占的比例只有2%，但哈佛的学生四分之一是犹太人；犹太人占全球人口比例约为0.3%，但是获得诺奖的比例却高达20%……&lt;/p&gt;
&lt;p&gt;但是，托马斯·索威尔特别提到，犹太人在很多行业都干得非常好，在农业领域就不行。美国的农业领域从没有出现过一家犹太农业巨头。&lt;/p&gt;
&lt;p&gt;别看现在以色列农业做得不错，那是工业化改造的农业。在欧洲和美国几百年的发展过程中，犹太人从来没有把农业做好过。因为，犹太人没有这方面的思维和行为习惯。换句网络流行语，就是犹太人没有搞农业的“种族天赋“。&lt;/p&gt;
&lt;p&gt;而中国人则不同。我们几千年来都是农业社会，已经达到了文明可以达到的巅峰。不管是生产力，还是文化，军事，政治，都创造了农业社会能达到的至高点。今天，中国人走到任何地方，第一件事就是把房前屋后的土地利用上，用来种菜。甚至，南海在大自然的鬼斧神工之下催生出了一批岛屿，我们的首要目的也是种上菜，“改善驻岛官兵的生活条件“。种菜，被认为是中国人的种族天赋。&lt;/p&gt;
&lt;p&gt;非常遗憾的是，现代社会，更需要工商业天赋，而不是种菜天赋。因此，中国人在工商业、金融业、政界、学界，暂时还竞争不过犹太人。因为我们还处于农业文明向工业文明的转型过程中。而犹太人，两千年来一致都是工商业文明。一遇到工业革命后的工业社会，就如鱼得水，迅速崛起。&lt;/p&gt;
&lt;h2 id=&#34;4&#34;&gt;&lt;a href=&#34;#4&#34; class=&#34;headerlink&#34; title=&#34;4&#34;&gt;&lt;/a&gt;4&lt;/h2&gt;&lt;p&gt;上面说的是从整体人群，或从文明/人种的角度而言，农业文明在现代社会的不适应性和工商业文明的适应性。其实，我们每一个人，拥有的是农业的乡土思维，还是工商业的现代思维，在社会上成功的概率有天壤之别。&lt;/p&gt;
&lt;p&gt;以下是我总结的乡土思维“七宗罪“。请对照一下，你有没有下面的毛病？这”七宗罪“，也许就是限制了你的发展空间，让你生活得那么艰难的原因。&lt;/p&gt;
&lt;p&gt;1）过于追求稳定，不敢冒风险&lt;/p&gt;
&lt;p&gt;我从体制内出来后，经常有朋友和我说，他们也想出来，可是不敢。也有很多非体制内的朋友，觉得现在的工作比较稳定，虽有种种不如意，且离自己的梦想十万八千里，但还是舍不得另起炉灶。这其实就是过于追求稳定的土味思维。&lt;/p&gt;
&lt;p&gt;农业社会最重视稳定，最害怕风险。儒家经典和史书记载里，中国人最喜欢的日子是风调雨顺，四时有序。因为农业生产必须稳定，有任何异常变动都可能造成颗粒无收。此外，自科举制以来，一千多年中国形成了根深蒂固的“学而优则仕”观念。一份稳定的工作，尤其是一个有保障的铁饭碗，在很多中国人心中成了最好的职业选择。&lt;/p&gt;
&lt;p&gt;西方社会主要是海洋文明，敢于冒风险，时刻都在处理不确定性。这种特质在农业社会没有太大用处。但是一旦进入工业时代，其威力就迅速发挥出来。文明特质与历史进程的匹配性，让西方国家超越了东方的中国、印度、奥斯曼，领先于世界。&lt;/p&gt;
&lt;p&gt;现代社会，时时刻刻都在发生变化，早已不是农业社会一辈子就守着几亩薄田，年复一年过同样日子的时候了。工商业社会，机遇是与风险成正比的。过于追求稳定，不能忍受不确定性，就会丧失很多机会。&lt;/p&gt;
&lt;p&gt;我们的父辈们更青睐体制内的工作，情有可原。因为他们大部分是农村出生、农村长大，或者刚刚洗脚上田。但是，80、90后的人，应该要学会拥抱不确定性，与不确定性共处。如果死抱着一份稳定的工作，或者被一个体制内职位束缚住，什么都不敢做，其实是乡土思维在限制你的未来。&lt;/p&gt;
&lt;p&gt;2）只混强关系圈，忽略弱关系&lt;/p&gt;
&lt;p&gt;亲戚、朋友、同学、老师、老乡，这些天然形成的，经常联系的关系，就是强关系。而从陌生开始建立联系，联系频率较少的关系，是弱关系。&lt;/p&gt;
&lt;p&gt;农业社会里，强关系是绝大部分人一辈子能接触的全部关系。儒家思想重要组成部分“礼”，其实就是弄明白每一个个体在强关系集合中所处的位置。费正清说，中国农村社会结构的核心就是家庭制度；而中国社会最重要的特点就是熟人社会。作为农业文明的巅峰，中国人的亲属关系可能是全世界分得最细致的，中文分出的叔叔、伯伯、舅舅、姨父、姑父等，英文里就一个uncle。&lt;/p&gt;
&lt;p&gt;而现代社会，更重要的可能是弱关系。因为，工商业时代的特征是市场主体发生交易，相互满足   ， 不是农业时代的自给自足或小范围交换的时代。因此，弱关系显得尤为重要。强关系由于交往的圈子相同，得到的外部信息太少，冗余信息太多。只有弱关系才能带来新鲜的、有价值的信息。&lt;/p&gt;
&lt;p&gt;所以，热衷于请客送礼，拉帮结派，建立和维护强关系纽带的思维将越来越落后于时代，而以信息和价值交换为主的弱关系思维，才更适合于当今的工商业时代需求。&lt;/p&gt;
&lt;p&gt;关于弱关系的价值，可参考《拼多多上市，80后创始人28个月做到身家800亿，凭的就是弱关系》（此文120万+阅读，影响了无数人）、《 人生最好的机会，往往来自弱关系》两篇文章。&lt;/p&gt;
&lt;p&gt;3）相信宿命论，而不是个人奋斗&lt;/p&gt;
&lt;p&gt;我们常常听人说，“这都是命”，“我哪有这么好的命”，“努力了也没用，结果还是一样”等。这些，其实都是土味思维。&lt;/p&gt;
&lt;p&gt;农业社会生产力落后，人的力量有限而自然的力量无穷，人们特别容易想象自己的一切都由老天决定。从社会形态来说，农业社会又太过凝固不变，一个人无论如何拼命奋斗，基本上没有可能改变自己的命运，由此形成了强烈的宿命论观点。即便是战乱时刻出来几个乱世英雄，或者科举中出来几个苦读成才的高官，也往往被人们认为是前世积德或文曲星下凡之类。&lt;/p&gt;
&lt;p&gt;中国的农民非常勤奋，但这种勤奋是为了活命而不得不干苦力的勤奋，而不是相信自己的勤奋能改变命运。只有读书人可以说通过寒窗苦读，走科举之路来逆天改命，但比例太少了，和99%的农民没有关系。&lt;/p&gt;
&lt;p&gt;西方社会自大航海时代以来，就有无数的个人通过努力奋斗改变了自己和家庭的命运，这种现象的普遍性，让西方社会形成了通过个人努力可以实现梦想的普遍预期，“美国梦”就是其具体体现。&lt;/p&gt;
&lt;p&gt;工商业时代，竞争永无休止，个人一定不能服输认命。你一停止奋斗，社会就把你抛在后头，阶层就把你踩在底下。个人奋斗，是让自己生活过得更好的必由之路。如果你认命，或者期望通过中彩票这样的运气来改善生活，那你必然会越过越艰难，越来越失望。&lt;/p&gt;
&lt;p&gt;4）喜欢屯东西，在不必要的地方拼命省钱&lt;/p&gt;
&lt;p&gt;每个家庭都有这么一位老人，什么东西都屯着，永远舍不得扔。家里都快站不下脚了，瓶瓶罐罐破铜烂铁摆得满屋都是，你要当垃圾扔掉，还得说你不会过日子。&lt;/p&gt;
&lt;p&gt;每个家庭也还有这么一位老人，宁愿早高峰挤一个小时公交车去大菜场买菜，也不愿意在楼下的菜店买，因为大菜场便宜几毛钱。吃剩的饭菜，一定舍不得扔掉，要么不顾自己早已经“三高”，硬撑着非要吃完，要么留到下一顿，下下顿，接着吃已经产生了无数有害于身体的亚硝酸盐的剩菜。&lt;/p&gt;
&lt;p&gt;这些，都是长期农业社会物质极度缺乏留下的后遗症。&lt;/p&gt;
&lt;p&gt;我们都知道，美国人喜欢搬家，一辆车就把所有东西装走，穿州过省，换个地方生活。而中国人，搬一次家，简直要了老命。这其中的区别，就在于美国人家里屯的不必要东西少，搬起来容易。去过外国人家里参观的，会发现非常简单整洁，空间感很好。而中国人的房子，无论多大，总是不够放东西。为什么北欧装修是极简风？因为北欧人已经习惯了工业化时代的生活，不要的东西就扔掉，需要的时候再买就是。&lt;/p&gt;
&lt;p&gt;在不必要的地方省钱，更是要命的毛病。有人总喜欢买最便宜的水果、面包，味道不好不说，还经常是烂的或快过期的，结果既没满足口腹之欲，又有害于身体。在工作上，有人喜欢买低配的电脑或手机，盗版的软件，结果用得处处不爽，每天心情都受影响，很多时候还耽误了工作。&lt;/p&gt;
&lt;p&gt;工商业社会，需要重视空间的价值，重视体验的价值，重视时间的价值。不要把农业社会的土味思维带进来，让自己活得憋屈难受，工作得不爽或低效。&lt;/p&gt;
&lt;p&gt;5）抱着复古心态，而不是拥抱未来&lt;/p&gt;
&lt;p&gt;前不久，当代最顶尖的数学家迈克尔·阿蒂亚宣称证明了“黎曼猜想”。后来大家发现，这位数学家原来是老糊涂了（有兴趣的朋友可参阅我的文章《 满屏的“黎曼猜想”，到底在讲些什么？》）。我想，还好这是现代，我们不会盲目接受老人，尤其是曾经很牛的老人的一切教导（中国在这方面吃过的亏还小吗？）。而在中国古代，人们总是认为，古人比今人厉害，老人比年轻人厉害，古代比现在厉害。&lt;/p&gt;
&lt;p&gt;农业社会的发展是平的，一千年过去，社会还是一个样子，人们的生活也还是一个样子。在这样的社会里，古人和老人的经验总是适用的。而由于社会没有变化，未来是无望的，人们就把美好希望都寄托在过去。中国文人爱幻想“上古时期”、“三王之治”，认为那是人类的黄金时代。&lt;/p&gt;
&lt;p&gt;直到工业革命后，人类才习惯于明天的生活会比今天更好，下一代的生活会比这一代更好。而中国人过上这样的日子，也才几十年。我们还没有能够把这种思维融入到骨子里。我们还会认为，学问是古人的高，药方是古人的好，认为自己人生所能达到的巅峰就是现在，不敢放弃现在去搏一个更好的未来。&lt;/p&gt;
&lt;p&gt;工商业时代，我们必须抛弃这种土味思维。我们要向年轻人学习，年轻人掌握新的技术、新的潮流，比我们厉害多了；我们要着眼未来，要相信凭自己的双手，能创造更好的未来。只有这样，才能跟上风口，跟上时代的步伐。&lt;/p&gt;
&lt;p&gt;6）平均主义思维&lt;/p&gt;
&lt;p&gt;在咨询工作中，我常常需要在各个企业访谈。我发现，在关于薪酬待遇的访谈中，不管是高管，还是中层，还是普通员工，每个人都觉得自己拿得少，而别人拿得多，说的最多的意见是，希望薪酬政策能体现“公平公正”。但也有少数人会说，希望薪酬政策能体现价值贡献，贡献大的多拿，贡献小的少拿。&lt;/p&gt;
&lt;p&gt;前一种思维，就是土味思维；后一种，才是现代思维。&lt;/p&gt;
&lt;p&gt;中国古代的继承制度是“诸子均分“制。家庭财产，会在各个儿子之间平分。只有皇位/爵位或名位等，采取嫡长子继承制，但是其他儿子也有会有相应的权利。&lt;/p&gt;
&lt;p&gt;而西方社会古代多采用“长子继承”制，爵位或全部家庭财产都由长子继承，其他儿子自谋出路去。&lt;/p&gt;
&lt;p&gt;由此产生的思维习惯是，中国人特别喜欢平均主义，圣人总结为“不患寡而患不均”。凡是要革命，一定要喊“均田地”、“均贫富”、“平均地权”等口号。&lt;/p&gt;
&lt;p&gt;在财富线性积累的农业时代，平均主义容易实现，也有其道理。但是在财富指数化增涨的工商业时代，这种思维就大大落后了。现代社会的财富分配，遵从着幂律分布，通俗来讲，80%的新增财富，会被20%的人拿到。一家公司80%的奖金，会被20%的人瓜分。现代社会，已经不可能再有平均主义。如果一个国家有平均主义，那就是大锅饭式的灾难再次重临。如果一个企业有平均主义，那就离倒闭不远了。&lt;/p&gt;
&lt;p&gt;如果你还抱着平均主义思维，你永远只会抱怨不公，每天负能量满满，牢骚满腹。不如抛弃平均主义土味思维，认清社会现实，多想想自己怎么进入那20%中去吧。&lt;/p&gt;
&lt;p&gt;7）时间观念的淡漠&lt;/p&gt;
&lt;p&gt;有一位特别优秀的求职者，希望来我公司就职。我看其简历无可挑剔，视频面试也感觉不错，于是约了合伙人一起面试。结果30分钟的面试时间，小伙子迟到了10分钟。合伙人坚决要求不招，我也只好把他遗憾劝退。&lt;/p&gt;
&lt;p&gt;守时，是现代工商业社会的基本素质之一。不守时，本质上是一种土味思维和习惯。&lt;/p&gt;
&lt;p&gt;农业社会的时间观念是“农时”，节气最重要，只要不误了节气，就不会误了农作。而农闲的时候，时间就完全失去了意义。所以，农业社会的人，对时间的精准性要求不高。&lt;/p&gt;
&lt;p&gt;当然，农业社会比热带地区好一点。热带地区的人们以采摘和捕猎维生，以季节来计算时间。什么季节去什么地方，就能吃到香蕉，或者逮到角马，这个时间的精准度就更差。所以我们可以看到，再不守时的中国人，到了非洲、印度、拉美，也简直要被当地人的不守时给气死。&lt;/p&gt;
&lt;p&gt;工商业社会就不同，货物的交割要精确到天，交通运输要精确到分，生产线上的操作要精确到秒，如果没有时间观念，很容易乱套。我们看到，发展得比较好的工业国家，德国、英国、北欧，都是极其守时的，而南欧就差一些，所以西班牙、葡萄牙、希腊经济就不行（当然还是好过农业国家）。&lt;/p&gt;
&lt;p&gt;前面说的是对他人时间的不尊重。另一个更要命的土味思维，是对自己的时间不尊重。&lt;/p&gt;
&lt;p&gt;一是使用低效率的工具或方式去做事。上面王小波的文章里写到的就是典型。现实生活中也有很多，明明买得起3小时到达的高铁票，非要买12小时到达的普票；明明打的10分钟可到，非要坐公交摇晃1小时；明明正版软件一分钟就能解决的事，非要用盗版软件花三个小时去完成；明明充个会员就能直接看剧，非要为了免费先看75秒广告……时间都被这些低效的东西给浪费了。&lt;/p&gt;
&lt;p&gt;二是把过多的时间花费在无益的事情上面。别人在学习，你在打游戏。别人在工作，你在刷抖音。游戏抖音5分钟，人间已过3小时，可你还乐此不疲。&lt;/p&gt;
&lt;p&gt;你有没有想过：你的时间价值，决定了你的工资。你认为你一个小时值多少钱，就是你能拿到的工资的最高点。如果你自己都认为自己的时间不值钱，你的工资怎么可能高得了呢？ &lt;/p&gt;
&lt;h2 id=&#34;5&#34;&gt;&lt;a href=&#34;#5&#34; class=&#34;headerlink&#34; title=&#34;5&#34;&gt;&lt;/a&gt;5&lt;/h2&gt;&lt;p&gt;我们必须得认识到，现代世界是工商业的世界，只有符合新时代需求的事情，才能产生价值；只有做出符合新时代需求的事情的人，才能赚到钱。土味思维，只会限制你，使你远离成功。&lt;/p&gt;
&lt;p&gt;以下是几点如何适应工商业时代的建议。&lt;/p&gt;
&lt;p&gt;1）研究工商业社会的需求&lt;/p&gt;
&lt;p&gt;工商业社会的需求和农业社会的需求是不同的。爬树、种田，是农业社会的需求；文学、体育、娱乐等是工商业社会的需求。这就是为什么爬树、种田不能加分，而蒋方舟、科比和刘翔被大学抢着要的原因。&lt;/p&gt;
&lt;p&gt;我们要从社会需求出发，而不是个人能力出发，去看待问题。&lt;/p&gt;
&lt;p&gt;你说你锯木头特别快、或者剪纸特别好、或者化妆术超越天龙八部里面的阿朱，对市场而言，这都没有意义。&lt;/p&gt;
&lt;p&gt;只有有人闲得无聊喜欢看人锯木头，有些追求高品质小众娱乐的人就是想学剪纸，有些希望展现更完美自我的女生就是喜欢学化妆，而且你能找到这些人，把自己推送给这些人，你的能力才有用武之地。&lt;/p&gt;
&lt;p&gt;所以，我们首先要学会去研究工商业社会的需求。这些需求还有很多很多，你能满足其中哪怕很小的一点，都能赚到很多的钱。&lt;/p&gt;
&lt;p&gt;2）培养适合工商业社会的思维&lt;/p&gt;
&lt;p&gt;首先是前面提到的土味思维“七宗罪”要坚决摈弃。&lt;/p&gt;
&lt;p&gt;除此外，你还要养成不靠关系，靠市场规则和个人奋斗的习惯；要终生学习，不懈努力，始终向上生长；要有长远眼光和投资思维，学会利用复利的力量；要注意树立个人品牌（弱关系社会，个人品牌无比重要）。&lt;/p&gt;
&lt;p&gt;这里的每一点，都值得写一篇5千字长文去阐述。只要你持续关注何加盐公众号，以后都能学到。&lt;/p&gt;
&lt;p&gt;3）锻炼工商业社会的生存发展能力&lt;/p&gt;
&lt;p&gt;我把这条放在最后，是因为从逻辑上，你先要知道市场有哪些需求，你应该具备哪些底层思维，然后再来锻炼相关的能力。只有这样，才能有的放矢，事半功倍，不至于走弯路。&lt;/p&gt;
&lt;p&gt;你要培养的能力，是从需求而来的，是在你的底层思维的帮助下培养和发挥的。至于具体什么能力，要看你对市场需求的把握程度和你的兴趣爱好特长而定。&lt;/p&gt;
&lt;p&gt;我可以举一些例子供你参考，但你自已也要思考和寻找：&lt;/p&gt;
&lt;p&gt;例如：如何帮助生产者提高效率、降低成本（相关的专业和技能：人工智能、机械制造、工程设计、信息化、管理学、会计学等等），如何帮助卖方迅速找到买方（相关的专业和技能：营销、电子商务、大数据、广告设计、市场策划等等），如何取悦后工业社会娱乐至上的民众（相关专业和技能：文学、艺术、体育等等，但是必须能达到高水平）等等。&lt;/p&gt;
&lt;p&gt;还有一些通用的必备能力，例如：理财能力（你需要学习理财知识），运动能力（你需要锻炼身体），统计分析能力（你需要具备一些基本的统计学知识），领导能力（你需要学习怎么驱动自己和他人），语言能力（你需要学会如何演讲，或者学一门或几门外语），写作能力（你需要经常动笔写东西）等等。总之，工商业社会需要什么，你就锻炼什么。只要自己有能力，不愁抓不住机会。&lt;/p&gt;
&lt;h2 id=&#34;6&#34;&gt;&lt;a href=&#34;#6&#34; class=&#34;headerlink&#34; title=&#34;6&#34;&gt;&lt;/a&gt;6&lt;/h2&gt;&lt;p&gt;中国农业社会持续了几千年，进入工商业社会，还没有多长时间。我们每一个人，或多或少都具有一些乡土味，这跟你在城市长大还是农村长大没有关系，而是来自于我们的历史传承，深埋在我们的骨髓里面。&lt;/p&gt;
&lt;p&gt;乡土味或现代味，并没有高低之分，但是有不同的适用环境。在工商业社会，乡土思维，会限制你成功，而现代思维，会帮助你发展。&lt;/p&gt;
&lt;p&gt;换句话说，你有多土，就会有多穷。洗掉土味，才能走向成功。&lt;/p&gt;
&lt;p&gt;作者简介：何加盐，一个专门研究牛人的牛人。曾在政府工作，后创立咨询公司，现为咨询顾问，公众号写手。和你一起了解牛人是怎么炼成的，从牛人的经历与方法中，获得思维与认知的提升。了解牛人，学习牛人，成为牛人，从关注何加盐开始&lt;/p&gt;
&lt;p&gt;本文转载地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/783yvYbdVoDjTTe-EgEbOw&#34;&gt;https://mp.weixin.qq.com/s/783yvYbdVoDjTTe-EgEbOw&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;作者：回首笑人间，高级Java工程师一枚，热爱研究开源技术，架构师社区合伙人！&lt;br&gt;目录&lt;/p&gt;
&lt;p&gt;什么是持续集成&lt;br&gt;Jenkins简介&lt;br&gt;Jenkins安装与启动&lt;br&gt;Jenkins插件安装&lt;br&gt;全局工具配置&lt;br&gt;自动安装&lt;br&gt;本地安装&lt;br&gt;代码上传至Git服务器&lt;br&gt;任务的创建与执行&lt;br&gt;Go项目&lt;br&gt;JAVA项目&lt;br&gt;什么是持续集成&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;br&gt;持续集成 Continuous integration ，简称CI&lt;/p&gt;
&lt;p&gt;随着软件开发复杂度的不断提高，团队开发成员间如何更好地协同工作以确保软件开发的质量已经慢慢成为开发过程中不可回避的问题。尤其是近些年来，敏捷（Agile） 在软件工程领域越来越红火，如何能在不断变化的需求中快速适应和保证软件的质量也显得尤其的重要。&lt;/p&gt;
&lt;p&gt;持续集成正是针对这一类问题的一种软件开发实践。它倡导团队开发成员必须经常集成他们的工作，甚至每天都可能发生多次集成。而每次的集成都是通过自动化的构建来验证，包括自动编译、发布和测试，从而尽快地发现集成错误，让团队能够更快的开发内聚的软件。&lt;/p&gt;
&lt;p&gt;持续集成具有的特点：&lt;/p&gt;
&lt;p&gt;它是一个自动化的周期性的集成测试过程，从检出代码、编译构建、运行测试、结果记录、测试统计等都是自动完成的，无需人工干预；&lt;br&gt;需要有专门的集成服务器来执行集成构建；&lt;br&gt;需要有代码托管工具支持，例如Git以及可视化界面Gogs的使用&lt;br&gt;持续集成的作用：&lt;/p&gt;
&lt;p&gt;保证团队开发人员提交代码的质量，减轻了软件发布时的压力；&lt;br&gt;持续集成中的任何一个环节都是自动完成的，无需太多的人工干预，有利于减少重复过程以节省时间、费用和工作量；&lt;br&gt;Jenkins简介&lt;br&gt;Jenkins，原名Hudson，2011年改为现在的名字，它 是一个开源的实现持续集成的软件工具。官方网站：&lt;a href=&#34;http://jenkins-ci.org/。&#34;&gt;http://jenkins-ci.org/。&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;Jenkins 能实施监控集成中存在的错误，提供详细的日志文件和提醒功能，还能用图表的形式形象地展示项目构建的趋势和稳定性。&lt;/p&gt;
&lt;p&gt;特点：&lt;/p&gt;
&lt;p&gt;易安装：仅仅两个docker命令即可从官网下载直接运行，无需额外的安装，更无需安装数据库；&lt;br&gt;易配置：提供友好的GUI配置界面；&lt;br&gt;变更支持：Jenkins能从代码仓库（Subversion/CVS）中获取并产生代码更新列表并输出到编译输出信息中；&lt;br&gt;支持永久链接：用户是通过web来访问Jenkins的，而这些web页面的链接地址都是永久链接地址，因此，你可以在各种文档中直接使用该链接；&lt;br&gt;集成E-Mail/RSS/IM：当完成一次集成时，可通过这些工具实时告诉你集成结果（据我所知，构建一次集成需要花费一定时间，有了这个功能，你就可以在等待结果过程中，干别的事情）；&lt;br&gt;JUnit/TestNG测试报告：也就是用以图表等形式提供详细的测试报表功能；&lt;br&gt;支持分布式构建：Jenkins可以把集成构建等工作分发到多台计算机中完成；&lt;br&gt;文件指纹信息：Jenkins会保存哪次集成构建产生了哪些jars文件，哪一次集成构建使用了哪个版本的jars文件等构建记录；&lt;br&gt;支持第三方插件：使得 Jenkins 变得越来越强大&lt;br&gt;Jenkins安装与启动&lt;br&gt;（1）执行安装命令,下载jenkins&lt;/p&gt;
&lt;p&gt;docker pull jenkins/jenkins&lt;br&gt;（2）启动服务&lt;/p&gt;
&lt;p&gt;docker run -p 8080:8080 -p 50000:50000 -v /mnt/data/jenkins:/var/jenkins_home —name “jenkins” jenkins/jenkins&lt;/p&gt;
&lt;p&gt;若报错如下:&lt;/p&gt;
&lt;p&gt;touch: cannot touch ‘/var/jenkins_home/copy_reference_file.log’: Permission denied&lt;br&gt;Can not write to /var/jenkins_home/copy_reference_file.log. Wrong volume permissions?&lt;br&gt;需要修改下目录权限, 因为当映射本地数据卷时，/mnt/data/jenkins目录的拥有者为root用户，而容器中jenkins user的uid为1000&lt;/p&gt;
&lt;p&gt;sudo chown -R 1000:1000 /mnt/data/jenkins&lt;br&gt;（3）访问链接 &lt;a href=&#34;http://10.20.29.151:8080&#34;&gt;http://10.20.29.151:8080&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;若密码忘记，可进入容器，执行cat /var/lib/jenkins/secrets/initialAdminPassword获取初始密码串。&lt;br&gt;若目录不存在，可使用find / -name “initialAdminPassword” -depth -print命令查找。&lt;/p&gt;
&lt;p&gt;（4）安装插件&lt;/p&gt;
&lt;p&gt;（5）新建用户&lt;/p&gt;
&lt;p&gt;完成安装进入主界面&lt;/p&gt;
&lt;p&gt;Jenkins插件安装&lt;br&gt;我们以安装maven插件为例，演示插件的安装&lt;/p&gt;
&lt;p&gt;（1）点击左侧的“系统管理”菜单 ,然后点击&lt;/p&gt;
&lt;p&gt;（2）选择“可选插件”选项卡，搜索maven，在列表中选择Maven Integration ，点击“直接安装”按钮&lt;/p&gt;
&lt;p&gt;看到如下图时，表示已经完成&lt;/p&gt;
&lt;p&gt;注:如果你的项目是GitHub、GitLib或是Go语言等项目，那么我想你都需要这么一个对应的插件来帮你干活。&lt;br&gt;全局工具配置&lt;br&gt;选择系统管理，全局工具配置&lt;/p&gt;
&lt;p&gt;自动安装&lt;/p&gt;
&lt;p&gt;Jenkins提供了两种工具配置的方式，我们还是以maven为例&lt;/p&gt;
&lt;p&gt;第一种如上图，只需要选择自动安装和版本号就可以，同时Jenkins在右上角给出了一个解疑按键，可以通过该键看到说明和示例。&lt;/p&gt;
&lt;p&gt;本地安装&lt;/p&gt;
&lt;p&gt;相较于第一种方式，第二种方式相对麻烦一些，但好处是可以在以后打包的时候不必重新下载，缩短打包的时间。&lt;/p&gt;
&lt;p&gt;下面就来教大家如何安装Maven与本地仓库：&lt;/p&gt;
&lt;p&gt;（1）将Maven压缩包上传至服务器（虚拟机）&lt;/p&gt;
&lt;p&gt;（2）解压&lt;/p&gt;
&lt;p&gt;tar zxvf apache-maven-3.5.4-bin.tar.gz&lt;br&gt;（3）移动目录&lt;/p&gt;
&lt;p&gt;mv apache-maven-3.5.4 /usr/local/maven&lt;br&gt;（4）编辑setting.xml配置文件vi /usr/local/maven/conf/settings.xml，配置本地仓库目录,内容如下&lt;/p&gt;
&lt;p&gt;&lt;localRepository&gt;/usr/local/repository&lt;/localRepository&gt;&lt;br&gt;（5）将开发环境的本地仓库上传至服务器（虚拟机）并移动到/usr/local/repository 。&lt;/p&gt;
&lt;p&gt;mv reponsitory_boot /usr/local/repository&lt;br&gt;其他示例:&lt;/p&gt;
&lt;p&gt;（1）JDK配置&lt;/p&gt;
&lt;p&gt;设置javahome为 /usr/java/jdk1.8.0_171-amd64&lt;/p&gt;
&lt;p&gt;（2）Git配置 （本地已经安装了Git软件）&lt;/p&gt;
&lt;p&gt;（3）Maven配置&lt;/p&gt;
&lt;p&gt;代码上传至Git服务器&lt;br&gt;步骤：&lt;/p&gt;
&lt;p&gt;（1）在本地安装git(Windows版本)&lt;/p&gt;
&lt;p&gt;（2）在IDEA中选择菜单 : File — settings , 在窗口中选择Version Control — Git&lt;/p&gt;
&lt;p&gt;（3）选择菜单VCS —&amp;gt; Enable Version Control Integration…&lt;/p&gt;
&lt;p&gt;选择Git&lt;/p&gt;
&lt;p&gt;（4）设置远程地址: 右键点击工程选择菜单 Git —&amp;gt; Repository —&amp;gt;Remotes…&lt;/p&gt;
&lt;p&gt;（5）右键点击工程选择菜单 Git —&amp;gt; Add&lt;/p&gt;
&lt;p&gt;（6）右键点击工程选择菜单 Git —&amp;gt; Commit Directory…&lt;/p&gt;
&lt;p&gt;（7）右键点击工程选择菜单 Git —&amp;gt; Repository —&amp;gt; Push …&lt;/p&gt;
&lt;p&gt;任务的创建与执行&lt;br&gt;我们以最火的Java项目和Go项目为例，给大家分别演示如何构建项目和执行&lt;/p&gt;
&lt;p&gt;Go项目&lt;/p&gt;
&lt;p&gt;（1）回到首页，点击新建按钮 .如下图，输入名称，选择创建一个自由风格的项目，点击OK&lt;/p&gt;
&lt;p&gt;（2）General管理，可以添加项目描述和GitHub项目路径，以及一些配置&lt;/p&gt;
&lt;p&gt;（3）源码管理，选择GitHub&lt;/p&gt;
&lt;p&gt;（4）构建触发器，配置触发规则，这里以定时和轮询为示例，配别设置为&lt;/p&gt;
&lt;p&gt;定时构建：定时构建1次任务&lt;/p&gt;
&lt;p&gt;轮询SCM:定时查看源码管理的代码是否更新，有更新则构建，否则不会构建&lt;/p&gt;
&lt;p&gt;如图所示，定时构建为每间隔10分钟定时构建一次，轮询SCM为每5分钟轮询检测一次。&lt;/p&gt;
&lt;p&gt;时间*号规则为: 分 时 日 月 周&lt;br&gt;（5）构建环境，配置控制台输出时间戳和指定Go语言版本&lt;/p&gt;
&lt;p&gt;（6）构建，使用Shell脚本测试代码上传后的项目是否有效&lt;/p&gt;
&lt;p&gt;Shell如下:&lt;/p&gt;
&lt;p&gt;export GOPATH=$WORKSPACE/../                    # 指定GOPATH路径，Go语言执行必须有GOPATH路径&lt;br&gt;export GOWORK=$GOPATH/src/github.com/Jenkins    # 创建项目执行时的目录依赖结构&lt;br&gt;cp -rf $WORKSPACE/* $GOWORK/                    # 使测试运行数据和源数据隔离&lt;br&gt;cd $GOWORK &amp;amp;&amp;amp; go build                          # 进入项目目录并执行&lt;br&gt;命令解说：&lt;/p&gt;
&lt;p&gt;$GOPATH Go 运行需要指定 GOPATH 也即项目运行路径&lt;br&gt;$WORKSPACE /var/jenkins_home/workspace/Jenkins&lt;br&gt;GOWORK 创建符合代码依赖的执行目录&lt;br&gt;注:下载Go的插件在构建时，会自动为我们设置GOROOT,但不会指定GOPATH，因此需要指定&lt;br&gt;最后点击“保存”按钮&lt;/p&gt;
&lt;p&gt;（7）执行构建，控制台查看输出&lt;/p&gt;
&lt;p&gt;构建成功，也输出了WORKSPACE、GOPATH、GOROOT目录，说明配置生效。进入docker容器或是挂载目录查看是否有可执行文件：&lt;/p&gt;
&lt;p&gt;除了上述方法，也可以通过shell配置docker等方式构建、部署、运行项目，还可以将项目配置到当前/其他服务器运行，更多配置方式就不一一陈述了，请自行挖掘。&lt;/p&gt;
&lt;p&gt;JAVA项目&lt;/p&gt;
&lt;p&gt;（1）回到首页，点击新建按钮 .如下图，输入名称，选择创建一个Maven项目，点击OK&lt;/p&gt;
&lt;p&gt;（2）源码管理，选择Git&lt;/p&gt;
&lt;p&gt;（3）Build&lt;/p&gt;
&lt;p&gt;命令:&lt;/p&gt;
&lt;p&gt;clean package docker:build -DpushImage&lt;br&gt;用于清除、打包，构建docker镜像&lt;/p&gt;
&lt;p&gt;最后点击“保存”按钮&lt;/p&gt;
&lt;p&gt;（4）执行任务&lt;/p&gt;
&lt;p&gt;后续请参照Go项目的执行步骤。&lt;br&gt;原创地址：&lt;a href=&#34;https://mp.weixin.qq.com/s/PEupc5YIKuctZO1Tivy_ug&#34;&gt;https://mp.weixin.qq.com/s/PEupc5YIKuctZO1Tivy_ug&lt;/a&gt;&lt;/p&gt;

 &lt;p&gt;想要从商业 CA 获取数字证书需要向其支付一定的金钱，不过我们不用那么破费，可以自己成为 root CA，为自己发布证书。&lt;/p&gt;
&lt;p&gt;在本实验中，我们将成为 root CA，并为该 CA 生成证书。不像其他 CA 需要被另外的 CA 认证， root CA 的证书是自己为自己认证的，一般 Root CA 的证书都已事先加载在大多数操作系统，浏览器或者依赖 PKI 的软件之中了。Root CA 的证书是被无条件信任的。&lt;br&gt;&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;配置文件：openssl.conf&lt;/p&gt;
&lt;p&gt;为了使用 openssl 生成证书，我们首先需要进行配置，配置文件扩展名为.cnf。openssl 的 ca， req， x509 命令常常会用到这份配置文件。你可以从 /usr/lib/ssl/openssl.cnf 获得一份拷贝。将文件拷贝到工作目录后，创建以下在配置文件中指定的子文件夹（详情查看配置文件[CA default]处）&lt;br&gt;首先我们新建一个工作目录：&lt;/p&gt;
&lt;p&gt;$ cd /home/shiyanlou&lt;/p&gt;
&lt;p&gt;$ mkdir openssl&lt;/p&gt;
&lt;p&gt;$ cd openssl&lt;/p&gt;
&lt;p&gt;需要的文件夹和文件配置在 openssl.cnf 中都能找到：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;dir = ./demoCA # Where everything is kept&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;certs = $dir/certs # Where the issued certs are kept&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;crl_dir = $dir/crl # Where the issued crl are kept&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;new_certs_dir = $dir/newcerts # default place for new certs.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;database = $dir/index.txt # database index file.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;serial = $dir/serial # The current serial number&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;br&gt;openssl.cnf 中相关配置截图：&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201907/ca1.png&#34; alt=&#34;ca截图&#34;&gt;&lt;/p&gt;
&lt;p&gt;在工作目录下我们需要创建如下这些文件夹和文件，这里给出文件目录树：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;|-- demoCA&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- certs&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- crl&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- index.txt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- newcerts&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   `-- serial&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;`-- openssl.cnf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;index.txt 只要创建空文件就行，至于 serial 文件，内容必须是字符串格式的数字（比如 1000）&lt;br&gt;具体执行命令如下：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ sudo cp /usr/lib/ssl/openssl.cnf .  &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ mkdir demoCA                                                                                 &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ cd demoCA                                              &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ mkdir certs crl newcerts                                                                     &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ touch index.txt                                                           &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ echo &amp;#x27;1000&amp;#x27; &amp;gt; serial                                                       &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ cd ..&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201907/ca2.png&#34; alt=&#34;ca截图&#34;&gt;&lt;br&gt;一旦你设置好 openssl.cnf 就可以创建和发布证书了。&lt;/p&gt;
&lt;p&gt;数字证书认证机构（CA）&lt;br&gt;我们需要为自己的 CA 生成自签名证书。这意味着该机构是被信任的，而它的证书会作为 root 证书。你可以运行以下命令为 CA 生成自签名证书：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ openssl req -new -x509 -keyout ca.key -out ca.crt -config openssl.cnf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;它要求你提供信息和密码，可千万别忘记密码了（我这里输入的密码是 shiyanlou），因为每次为别人签证书的时候你都需要用到密码。信息包括城市名，通用名等等。命令的输出存储在两个文件中：ca.key 与 ca.crt 中。文件 ca.key 包括 CA 的私钥，而 ca.crt 包含了公钥证书。&lt;br&gt;&lt;img src=&#34;/img/201907/ca3.png&#34; alt=&#34;ca截图&#34;&gt;&lt;/p&gt;
&lt;p&gt;现在，我们是 root CA 了，我们已经准备好为我们的客户签数字证书，我们的第一个客户是叫作 PKILabServer.com 的公司，这家公司从 CA 获取数字证书需要 3 个步骤：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;生成公开/私有密钥对&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;该公司首先需要生成它自己的公开/私有密钥对。我们运行以下命令来生成 RSA 密钥对。你同时需要提供一个密码来保护你的密钥（我这里设置的密码是 pkilab）。密钥会被保存在 server.key 文件中。&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ openssl genrsa -des3 -out server.key 1024&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;/img/201907/ca4.png&#34; alt=&#34;ca截图&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;生成证书签名请求&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;一旦公司拥有了密钥文件，它应当生成证书签名请求（CSR）。CSR 将被发送给 CA，CA 会为该请求生成证书（通常在确认 CSR 中的身份信息匹配后）。请将 PKILabServer.com 作为证书请求的通用名，并且请记住自己都输了些啥。&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;$ openssl req -new -key server.key -out server.csr -config openssl.cnf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;最开始输入的密码就是我们上面设置的密码（pkilab）&lt;br&gt;&lt;img src=&#34;/img/201907/ca5.png&#34; alt=&#34;ca截图&#34;&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;生成证书&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;生成证书。CSR 文件需要拥有 CA 的签名来构成证书。在现实世界中，CSR 文件常常被发送给可信任的 CA 签名。本实验中，我们将使用我们自己的 CA 来生成证书：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;$ openssl ca -in server.csr -out server.crt -cert ca.crt -keyfile ca.key -config openssl.cnf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;p&gt;输入的密码是我们在第一步设置的密码（shiyanlou）&lt;br&gt;&lt;img src=&#34;/img/201907/ca6.png&#34; alt=&#34;ca截图&#34;&gt;&lt;/p&gt;
&lt;p&gt;如果 OpenSSL 拒绝生成证书，那很可能是因为你请求中的名字与 CA 所持有的不匹配。匹配规则在配置文件中指定([policy match]处)，你可以更改名字也可以更改规则。都做到这了，就改规则吧。&lt;br&gt;此时的目录结构如下：&lt;br&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;.&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|-- ca.crt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|-- ca.key&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|-- demoCA&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- certs&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- crl&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- index.txt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   |-- newcerts&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|   `-- serial&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|-- openssl.cnf&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|-- server.crt&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;|-- server.csr&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;`-- server.key&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/p&gt;
&lt;h1 id=&#34;本文来源于实验楼&#34;&gt;&lt;a href=&#34;#本文来源于实验楼&#34; class=&#34;headerlink&#34; title=&#34;本文来源于实验楼&#34;&gt;&lt;/a&gt;&lt;a href=&#34;#本文来源于实验楼&#34; title=&#34;本文来源于实验楼&#34;&gt;&lt;/a&gt;本文来源于&lt;a href=&#34;https://www.shiyanlou.com&#34;&gt;实验楼&lt;/a&gt;&lt;/h1&gt;
